104:                     polarity,
105:                 })) => Some(PredicateKind::Clause(ClauseKind::Trait(TraitPredicate {
106:                     trait_ref,
107:                     polarity: polarity.flip(),
108:                 }))),
109: 
110:                 _ => None,
111:             })
112:             .transpose()?;
113: 
114:         Some(tcx.mk_predicate(kind))
115:     }
