742: impl<I: Interner> From<ty::AliasTy<I>> for AliasTerm<I> {
743:     fn from(ty: ty::AliasTy<I>) -> Self {
744:         AliasTerm { args: ty.args, def_id: ty.def_id, _use_alias_term_new_instead: () }
745:     }
